  extractImagesFromPost() {
    const htmlContent = this.attrs.post.contentHtml();
    const tempDiv = document.createElement('div');
    tempDiv.innerHTML = htmlContent;
    const imgs = tempDiv.querySelectorAll('img');
    let images = [];
    imgs.forEach((img) => {
      let src = img.getAttribute('src');
      if (src) { images.push(src.replace('thumb_', '')); } 
    });
    return images;
  }

  extractPostDetails() {
    const post = this.attrs.post;
    const html = post.contentHtml();
    const tempDiv = document.createElement('div');
    tempDiv.innerHTML = html;

    const listItems = Array.from(tempDiv.querySelectorAll('ul li')).map(li => li.innerText.trim());
    const companyName = listItems[0] ? (listItems[0].includes('|') ? listItems[0].split('|')[0].trim() : listItems[0]) : '';
    const modelName = listItems[1] || '';
    const topicTitle = post.discussion().title();
    const authorName = post.user() ? post.user().displayName() : '';

    return { topicTitle, companyName, modelName, authorName };
  }

  async fetchExifFromPHP(imageUrl) {
    if (!imageUrl) return;
    try {
        const phpUrl = app.forum.attribute('baseUrl') + '/get_exif.php?url=' + encodeURIComponent(imageUrl);
        const response = await fetch(phpUrl);
        const json = await response.json();
        
        if (json && json.success && json.data) {
            const data = json.data;
            let updated = false;
            
            if (data.camera && !this.exifData.camera) { this.exifData.camera = data.camera; updated = true; }
            if (data.lens && !this.exifData.lens) { this.exifData.lens = data.lens; updated = true; }
            if (data.shutter && !this.exifData.shutter) { this.exifData.shutter = data.shutter; updated = true; }
            if (data.aperture && !this.exifData.aperture) { this.exifData.aperture = data.aperture; updated = true; }
            if (data.iso && !this.exifData.iso) { this.exifData.iso = data.iso; updated = true; }
            if (data.focal && !this.exifData.focal) { this.exifData.focal = data.focal; updated = true; }
            
            if (updated) {
                m.redraw();
                this.updateCanvasSync();
            }
        }
    } catch (e) {
        console.warn("Sunucu üzerinden EXIF çekilemedi.", e);
    }
  }

  extractExifFromDOM() {
    let exif = { camera: '', lens: '', shutter: '', aperture: '', iso: '', focal: '' };
    try {
        const postId = this.attrs.post.id();
        const postDom = document.querySelector(`[data-id="${postId}"]`) || document.querySelector(`.PostStream-item[data-id="${postId}"]`);
        if (!postDom) return exif;
        
        const walker = document.createTreeWalker(postDom, NodeFilter.SHOW_TEXT, null, false);
        let textNodes = [];
        let node;
        while (node = walker.nextNode()) {
            let text = node.nodeValue.replace(/[\n\r]+|[\s]{2,}/g, ' ').trim();
            if (text && text !== ':' && text !== '-') textNodes.push(text);
        }

        for (let i = 0; i < textNodes.length; i++) {
            const text = textNodes[i].toUpperCase();
            if ((text === 'KAMERA' || text === 'GÖVDE') && textNodes[i+1]) exif.camera = textNodes[i+1];
            else if (text === 'LENS' && textNodes[i+1]) exif.lens = textNodes[i+1];
            else if (text === 'ENSTANTANE' && textNodes[i+1]) exif.shutter = textNodes[i+1];
            else if (text === 'DİYAFRAM' && textNodes[i+1]) exif.aperture = textNodes[i+1];
            else if (text === 'ISO' && textNodes[i+1]) exif.iso = textNodes[i+1];
            else if (text === 'ODAK UZAKLIĞI' && textNodes[i+1]) exif.focal = textNodes[i+1];
        }

        const stopWords = ['KAMERA', 'LENS', 'ENSTANTANE', 'DİYAFRAM', 'ISO', 'ODAK UZAKLIĞI', 'ÇEKİM TARİHİ', 'FOTOĞRAF BİLGİLERİ'];
        for (let key in exif) {
            if (exif[key] && stopWords.some(w => exif[key].toUpperCase() === w)) exif[key] = ''; 
        }
    } catch (e) {}
    return exif;
  }

