import Modal from 'flarum/common/components/Modal';
import Button from 'flarum/common/components/Button';
import Stream from 'flarum/common/utils/Stream';

export default class ShareModal extends Modal {
  oninit(vnode) {
    super.oninit(vnode);

    this.pageId = app.forum.attribute('framio-social-share.page_id');
    this.igId = app.forum.attribute('framio-social-share.ig_id');
    this.token = app.forum.attribute('framio-social-share.token');

    const formatted = this.formatPostContent();
    this.message = Stream(formatted);
    this.scheduleTime = Stream('');
    this.availableImages = this.extractImagesFromPost();
    this.selectedImages = [...this.availableImages];
    this.platforms = { facebook: true, instagram: true };
    this.previewIndex = 0;
    this.previewMode = 'facebook';
    this.textExpanded = false;
    this.loading = false;
  }

  formatPostContent() {
    const post = this.attrs.post;
    const html = post.contentHtml();
    const tempDiv = document.createElement('div');
    tempDiv.innerHTML = html;

    const title = post.discussion().title().toUpperCase();
    const url = app.forum.attribute('baseUrl') + '/d/' + post.discussion().slug();
    const authorName = post.user() ? post.user().displayName() : 'Anonim';

    const listItems = Array.from(tempDiv.querySelectorAll('ul li')).map(li => li.innerText.trim());
    const line1 = listItems[0] || '';
    const line2 = listItems[1] || '';
    const line3 = listItems[2] || '';
    
    const companyName = line1.includes('|') ? line1.split('|')[0].trim() : line1;
    let city = line3;
    let year = '';
    if (line3.includes('/')) {
      const parts = line3.split('/');
      city = parts[0].trim();
      year = parts[1] ? parts[1].trim() : '';
    }

    const ulElement = tempDiv.querySelector('ul');
    if (ulElement) ulElement.remove();

    let bodyText = tempDiv.innerHTML.replace(/<br\s*\/?>/mg, '\n').replace(/<\/p>/mg, '\n\n').replace(/<[^>]+>/g, '').trim();

    const triviaMatch = bodyText.match(/(?:TRIVIA|Trivia|T R I V I A|Meraklısına Info|Meraklisina Info|MERAKLISINA INFO)(?:\s*:)?\s*([\s\S]*?)(?=\n\n|$)/i);
    let triviaSection = '';
    if (triviaMatch) {
      const isUlasim = triviaMatch[0].toUpperCase().includes('INFO');
      const prefix = isUlasim ? 'Meraklısına Info :\n\n' : 'T R I V I A :\n\n';
      
      triviaSection = prefix + triviaMatch[1].trim();
      bodyText = bodyText.replace(triviaMatch[0], '').trim();
    }

    let template = app.forum.attribute('framio-social-share.post_template');
    if (!template) {
        template = "{sirket} & {madde_2}\n\n{trivia}\n{icerik}\n\nDaha fazlası için bizi takip etmeyi unutmayın: @spottersturkeycom | forum.spottersturkey.com\n\n> {madde_1}\n> {madde_2}\n> {sehir}\n\n📸: {yazar} / {yil}";
    }

    let finalPost = template
      .replace(/{baslik}/g, title)
      .replace(/{sirket}/g, companyName)
      .replace(/{sehir}/g, city)
      .replace(/{yil}/g, year)
      .replace(/{yazar}/g, authorName)
      .replace(/{link}/g, url)
      .replace(/{madde_1}/g, line1)
      .replace(/{madde_2}/g, line2)
      .replace(/{madde_3}/g, line3)
      .replace(/{trivia}/g, triviaSection)
      .replace(/{icerik}/g, bodyText);

    finalPost = finalPost.replace(/>\s*\n/g, '').replace(/\n{3,}/g, '\n\n').trim();

    return finalPost;
  }

  extractImagesFromPost() {
    const htmlContent = this.attrs.post.contentHtml();
    const tempDiv = document.createElement('div');
    tempDiv.innerHTML = htmlContent;
    const imgs = tempDiv.querySelectorAll('img');
    let images = [];
    imgs.forEach((img) => {
      let src = img.getAttribute('src');
      if (src) { images.push(src.replace('thumb_', '')); }
    });
    return images;
  }

  className() { return 'FramioShareModal'; }
  title() { return 'Meta\'da Paylaş'; } 

  content() {
    if (this.previewIndex >= this.selectedImages.length) this.previewIndex = 0;
    const currentPreviewImage = this.selectedImages.length > 0 ? this.selectedImages[this.previewIndex] : null;

    const fullText = this.message();
    const limit = this.previewMode === 'facebook' ? 200 : 150;
    const isLongText = fullText.length > limit;
    const displayText = this.textExpanded ? fullText : (isLongText ? fullText.substring(0, limit) + '...' : fullText);

    return (
      <div className="Modal-body">
        
        {/* SIDEBAR */}
        <div className="Framio-Sidebar">
          <div className="Sidebar-Section">
            <h3>Medya Seçimi ({this.selectedImages.length})</h3>
            <div className="Media-Grid">
              {this.availableImages.map((url) => {
                const isSelected = this.selectedImages.includes(url);
                const order = this.selectedImages.indexOf(url) + 1;
                return (
                  <div className={`Media-Item ${isSelected ? 'selected' : ''}`} onclick={() => this.toggleImage(url)}>
                    <img src={url} />
                    {isSelected && <div className="Selection-Badge">{order}</div>}
                  </div>
                );
              })}
            </div>
          </div>

          <div className="Sidebar-Section" style="border-bottom:none; flex:1;">
            <div className="Form-Group">
              <label>Platformlar</label>
              <div className="Platform-Checkboxes">
                <button type="button" className={`Platform-Btn fb ${this.platforms.facebook ? 'active' : ''}`} onclick={() => this.platforms.facebook = !this.platforms.facebook}><i className="fab fa-facebook"></i> Facebook</button>
                <button type="button" className={`Platform-Btn ig ${this.platforms.instagram ? 'active' : ''}`} onclick={() => this.platforms.instagram = !this.platforms.instagram}><i className="fab fa-instagram"></i> Instagram</button>
              </div>
            </div>

            <div className="Form-Group">
              <label>Metin Düzenle</label>
              <textarea className="FormControl" value={this.message()} oninput={(e) => this.message(e.target.value)} />
            </div>

            <div className="Form-Group">
              <label>Zamanlama (Opsiyonel)</label>
              <input type="datetime-local" className="FormControl" oninput={(e) => this.scheduleTime(e.target.value)} value={this.scheduleTime()} />
            </div>
          </div>

          <div className="Action-Area">
            <Button className="Button Button--primary Button--block Button--large" loading={this.loading} onclick={this.onsubmit.bind(this)} disabled={this.selectedImages.length === 0}>
              {this.scheduleTime() ? <><i className="fas fa-clock"></i> Zamanla</> : <><i className="fas fa-paper-plane"></i> Paylaş</>}
            </Button>
          </div>
        </div>

        {/* PREVIEW */}
        <div className="Framio-Preview-Col">
          <div className="Preview-Switcher">
            <button type="button" className={this.previewMode === 'facebook' ? 'active fb-mode' : ''} onclick={() => this.previewMode = 'facebook'}><i className="fab fa-facebook"></i> Facebook</button>
            <button type="button" className={this.previewMode === 'instagram' ? 'active ig-mode' : ''} onclick={() => this.previewMode = 'instagram'}><i className="fab fa-instagram"></i> Instagram</button>
          </div>

          {/* Facebook */}
          {this.previewMode === 'facebook' ? (
            <div className="Preview-Card Facebook-Card">
              <div className="Post-Header">
                <img className="Avatar" src={app.forum.attribute('faviconUrl')} />
                <div className="Info"><span className="Name">Spotters Turkey</span><span className="Time">Az önce • <i className="fas fa-globe-americas"></i></span></div>
              </div>
              
              <div className="Post-Text">
                {displayText}
                {isLongText && (
                  <span className="SeeMore-Btn" onclick={() => this.textExpanded = !this.textExpanded}>
                    {this.textExpanded ? ' (Daha Azını Gör)' : ' ... Devamını Gör'}
                  </span>
                )}
              </div>

              {currentPreviewImage && (
                <div className="Post-Image-Container">
                  <img src={currentPreviewImage} />
                  {this.selectedImages.length > 1 && (
                    <>
                      <button type="button" className="Nav-Btn prev" onclick={() => this.changePreview(-1)}><i className="fas fa-chevron-left"></i></button>
                      <button type="button" className="Nav-Btn next" onclick={() => this.changePreview(1)}><i className="fas fa-chevron-right"></i></button>
                    </>
                  )}
                </div>
              )}

              <div className="Post-Footer">
                <div><i className="far fa-thumbs-up"></i> Beğen</div>
                <div><i className="far fa-comment-alt"></i> Yorum Yap</div>
                <div><i className="far fa-share-square"></i> Paylaş</div>
              </div>
            </div>
          ) : (
            /* Instagram */
            <div className="Preview-Card Instagram-Card">
              <div className="Post-Header">
                <img className="Avatar" src={app.forum.attribute('faviconUrl')} />
                <span className="Name">spottersturkeycom</span> 
                <i className="fas fa-ellipsis-h" style={{ marginLeft: 'auto' }}></i>
              </div>

              {currentPreviewImage && (
                <div className="Post-Image-Container">
                  <img src={currentPreviewImage} />
                  {this.selectedImages.length > 1 && (
                    <>
                      <button type="button" className="Nav-Btn prev" onclick={() => this.changePreview(-1)}><i className="fas fa-chevron-left"></i></button>
                      <button type="button" className="Nav-Btn next" onclick={() => this.changePreview(1)}><i className="fas fa-chevron-right"></i></button>
                      <div className="Counter">{this.previewIndex + 1}/{this.selectedImages.length}</div>
                    </>
                  )}
                </div>
              )}

              <div className="Action-Bar">
                <i className="far fa-heart"></i>
                <i className="far fa-comment"></i>
                <i className="far fa-paper-plane"></i>
                <i className="far fa-bookmark" style={{ marginLeft: 'auto' }}></i>
              </div>

              <div className="Likes-Section">1.245 beğenme</div>

              <div className="Caption-Section">
                <span className="Username">spottersturkeycom</span> 
                {displayText}
                {isLongText && (
                  <span className="SeeMore-Btn" onclick={() => this.textExpanded = !this.textExpanded}>
                    {this.textExpanded ? ' (daha az)' : ' ... devamı'}
                  </span>
                )}
                <div className="Time">2 DAKİKA ÖNCE</div>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  changePreview(direction) {
    const len = this.selectedImages.length;
    this.previewIndex = (this.previewIndex + direction + len) % len;
  }

  toggleImage(url) {
    if (this.selectedImages.includes(url)) {
      this.selectedImages = this.selectedImages.filter(img => img !== url);
    } else {
      this.selectedImages.push(url);
    }
  }

  onsubmit(e) {
    e.preventDefault();
    if (this.selectedImages.length === 0) { alert('Fotoğraf seç!'); return; }

    const isScheduled = this.scheduleTime();
    const confirmationText = isScheduled 
        ? 'Gönderi ileri bir tarihe zamanlanacak. Onaylıyor musunuz?' 
        : 'Gönderi şu an hesaplarınızda paylaşılacak. Onaylıyor musunuz?';

    if (!confirm(confirmationText)) {
        return; 
    }

    this.loading = true;
    
    const finalPageId = this.platforms.facebook ? this.pageId : null;
    const finalIgId = this.platforms.instagram ? this.igId : null;

    app.request({
      method: 'POST',
      url: app.forum.attribute('apiUrl') + '/framio/social-share',
      body: { 
        message: this.message(), 
        images: this.selectedImages, 
        pageId: finalPageId, 
        igId: finalIgId, 
        token: this.token, 
        scheduleTime: this.scheduleTime() 
      }
    }).then((res) => {
      this.loading = false; 
      this.hide(); 
      app.alerts.show({ type: res.success ? 'success' : 'error' }, res.success ? 'Başarılı!' : 'Hata: ' + (res.errors ? res.errors.join(', ') : 'Hata'));
    }).catch(() => { 
      this.loading = false; 
      app.alerts.show({ type: 'error' }, 'Sunucu hatası.'); 
    });
  }
}