import app from 'flarum/forum/app';
import { extend } from 'flarum/common/extend';
import PostControls from 'flarum/forum/utils/PostControls';
import Button from 'flarum/common/components/Button';
import ShareModal from './components/ShareModal';
import StoryGeneratorModal from './components/StoryGeneratorModal';

app.initializers.add('framio-social-share', () => {
  extend(PostControls, 'moderationControls', function (items, post) {
    
    // 1. GÜVENLİK KAPISI: Ziyaretçileri (Giriş yapmamış kişileri) engelle
    if (!app.session.user) return;

    // 2. YETKİ KONTROLÜ: Kullanıcının gruplarını al
    const userGroups = app.session.user.groups();
    let isAuthorized = false;

    // Kullanıcının grupları içinde Admin (1) veya Moderatör (4) var mı diye bakıyoruz
    if (userGroups) {
        isAuthorized = userGroups.some(group => ['1', '4'].includes(group.id()));
    }

    // Eğer yetkisi yoksa, kodun geri kalanını çalıştırma (Butonları ekleme)
    if (!isAuthorized) return;

    // SADECE YETKİLİLERE GÖSTERİLECEK BUTONLAR
    items.add(
      'framio-social-share',
      Button.component(
        {
          icon: 'fas fa-share-alt',
          onclick: () => app.modal.show(ShareModal, { post: post }),
        },
        'Meta\'da Paylaş'
      )
    );

    items.add(
      'framio-story-generator',
      Button.component(
        {
          icon: 'fas fa-mobile-alt', 
          onclick: () => app.modal.show(StoryGeneratorModal, { post: post }),
        },
        'Hikaye (Story) Tasarla'
      )
    );
  });
});